INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00059', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「作為當時文人領袖、重建東林書院的顧憲成，其從商的父親早年就對小說，尤其是《水滸 傳》特別有興趣。清道光時徽州商人舒遵剛也說：『人皆讀四子書，及長習為商賈，置不復 問，有暇則觀演義說部。』由此可知，自十六世紀以後小說與戲曲已經成為通俗文化的核心， 並且由文人與商人所共享。」 根據上文，下列選項何者正確？', '["士與商的界線在十六世紀漸漸消融", "《水滸傳》為當時普遍的童蒙讀物", "雅文化成為士與商之間共同的語言", "明清時期小說與戲曲為商人所獨享"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00060', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「地瓜粥是粥中之質樸者，□□□□的樣子，它很隨和，很坦白，很善良，可以簡單搭配豆 腐、蛋、醬菜，也可奢華到有魚有肉有鮮蔬。」根據文意，引文中的□□□□應填入下列何 者最適當？', '["富甲一方", "權傾一時", "一介布衣", "一枝獨秀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00061', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「茶的原鄉在中國，自古發展迄今，已由原初的解渴藥飲、煎煮點啜，到今日的沖泡慢品。 隨著製茶方式的改變，茶器形式與品茗方法也隨之變化。漢地飲茶習俗，透過使臣與貿易的 傳播，也漸漸融入蒙藏人民的生活，發展出游牧民族的飲茶方式與器皿。」 根據上文，下列選項何者最符合文意？', '["藉由貿易往來，茶才得以從蒙藏傳入中國", "中國的飲茶文化，由實用發展到注重品味", "游牧民族飲茶方式，與漢人地區大同小異", "製茶技術的進步，讓沏茶的時間越來越短"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00062', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「可以賞，可以無賞，賞之過乎仁；可以罰，可以無罰，罰之過乎義。過乎仁，不失爲君子； 過乎義，則流而入於忍人。故仁可過也，義不可過也。」 根據上文，下列選項最符合文意的是：', '["賞罰忠厚", "居仁由義", "民胞物與", "天道酬勤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00063', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「漢末，朱雋圍黃巾於宛，張圍結壘，起土山以臨城內，鳴鼓攻其西南，黃巾悉眾赴之，雋 自將精兵五千，掩其東北，遂乘虛而入。」 下列選項最接近本文所運用的戰術是：', '["借刀殺人", "以逸待勞", "破釜沉舟", "聲東擊西"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00064', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「從沒有人因為缺乏香料而死，但卻有成千上萬的人——包括掠奪者和受害者為它而死。控 制豆蔻、肉桂和黑胡椒等重要香料交易而產生的私欲，使歐洲商業強權犯下許多暴行。然而， 若沒有香料貿易帶來的財富，恐怕根本不會發生文藝復興。大仲馬曾說：『在香料刺激造成 的興奮影響之下，智能的表現達到高峰。提香的畫作是否香料的功勞？我忍不住要這麼想。』」 根據上文，關於香料的敘述，不符合文意的是：', '["歐洲商業強權爭奪香料控制權時，曾殘忍的傷害許多人", "香料是生活必需品，不可缺乏，所以引發激烈的爭奪戰", "香料貿易所帶來的財富，有助歐洲文藝復興運動的推動", "大仲馬認為提香的繪畫成就，可能受到香料刺激的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00065', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「古代文人多年以來，受傳統影響，最愛講道理，不談事功。在帝制下的臣相賢士，只是向 君王個人盡責，肯不肯多做事沒大關係。因此，老成持重，乃是最高的大臣風範。王安石這 位首相不來這一套，他明知『遠世有百善，一疵惡皆歸，就求無所得，猶以好名譏』，還是 勉力而為，八年新政雖說未竟，但他那種開創、喜事，與愛國精神，是不該抹殺的。」 根據上文，下列選項何者最接近作者的觀點？', '["肯定王安石勇於任事，能夠以新政實踐理想", "文人只要盡責愛國，尊重傳統，就能博得美名", "文人多以建功立業為尚，展現老成持重的大臣風範", "稱許王安石明知新政有瑕疵，仍勉力而為的開創精神"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00066', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「叔本華說過這樣的話：要估定人的偉大，則精神上的大和體格上的大，那法則完全相反。 後者距離愈遠即愈小，前者卻見得愈大。正因為近則愈小，而且愈看見缺點和創傷，所以他 就和我們一樣，不是神道，不是妖怪，不是異獸。他仍然是人，不過如此。但也惟其如此， 所以他是偉大的人。戰士戰死了的時候，蒼蠅們所首先發現的是他的缺點和傷痕，嘬著，營 營地叫著，以為得意，以為比死了的戰士更英雄。但是戰士已經戰死了，不再來揮去他們。 於是乎蒼蠅們即更其營營地叫，自以為倒是不朽的聲音，因為它們的完全，遠在戰士之上。 的確的，誰也沒有發現過蒼蠅們的缺點和創傷。然而，有缺點的戰士終竟是戰士，完美的蒼 蠅也終竟不過是蒼蠅。」 根據上文，下列選項最接近作者旨趣的是：', '["全文譏刺偉人仍不免有瑕疵，而如蒼蠅般的小人亦有價值", "戰士之所以偉大，是因為具備「精神上的大」與「體格上的大」", "「精神上的大」，距離越近越能看見缺點和創傷，所以偉人和凡人一樣", "「體格上的大」，距離越遠所見越小，意謂局外人對事物的觀察將更細微"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00067', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「三國時期，晉、吳相爭，吳國大將陸抗生了一場大病，對手晉國大將羊祜善於用兵，且兼 通醫道，派人送了一帖藥給陸抗。陸抗毫不猶疑將藥服用，部屬勸止，擔心羊祜的藥是否可 靠。陸抗說：『羊祜豈鴆人者。』意思是羊祜縱然在沙場與我為敵，但『藥』就是『藥』。 沙場爭馳是一回事，但醫人是另一回事。」 根據上文，下列選項何者最符合文意？', '["陸抗跟羊祜本來就是好朋友", "人道主義應該超越敵我意識", "兩軍對陣不是你死就是我活", "羊祜送藥給陸抗是通敵行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00068', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '頃歲孫莘老識歐陽文忠公，嘗乘閒以文字問之，云：「無它術，唯勤讀書而多為之，自工。 世人患作文字少，又嬾讀書，每一篇出，即求過人，如此少有至者。疵病不必待人指擿，多 作自能見之。」此公以其嘗試者告人，故尤有味。（《東坡志林》） 文中歐陽脩所言，下列選項何者最符合文意？', '["勤讀各種書籍，自然能寫得出佳作", "世人讀書太少，故難掌握撰文訣竅", "只期待每篇盡屬佳作，則不免得罪人", "勤讀書多寫作，便能知自己文章問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
